  try {
    req.user = verifyJwt(token); // your verifier
    next();
  } catch {
    res.status(401).json({ error: 'unauthorized' });
  }
};

app.get('/users', requireAuth, (req, res) => {
  // Return only non-sensitive fields unless the caller is an admin.
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com' },
  ];
  const safe = users.map(({ id, name, email }) =>
    req.user.role === 'admin' ? { id, name, email } : { id, name }
  );
  res.json(safe);
